INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-7c4986e7-moex-00215', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-111-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司經營家電用品產銷業務，其銷售的電冰箱均附有一年的售後服務保證，顧客購買冰箱 後，在一年內如因製造瑕疵而發生故障，均由甲公司免費更換零件及維修，重大瑕疵則由甲 公司更換新電冰箱。根據經驗，電冰箱如發生製造小瑕疵，平均一台維修費用（連工帶料） 約為$1,875，如為大瑕疵，平均一台損失大約$3,750。甲公司110年共銷售電冰箱100,000台， 根據過去經驗，大約有4%會發生小瑕疵，1%會發生大瑕疵。請問110年12月31日產品服 務保證負債準備金額為多少？', '["$7,500,000", "$8,850,000", "$9,000,000", "$11,250,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:26+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "322", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00216', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-111-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司110年初發行面額$15,000,000的公司債流通在外，票面利率6%，10年期，每年6月 30日及12月31日付息，折價發行，於110年6月30日付息（並攤銷折價）後，其帳面金 額為$14,700,000。當日甲公司以98的價格從公開市場買回面額$3,750,000的公司債註銷，付 手續費$2,970。請問110年6月30日買回分錄，下列敘述何者正確？', '["借方「應付公司債折價」$75,000", "貸方「現金」$3,675,000", "借方「償債損益」$2,970", "貸方「應付公司債折價」$70,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:26+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "322", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00217', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-111-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司新進會計人員使用間接法編製現金流量表，111 年相關資料如下：購買一台機器付款 $240,000，該年度有員工認股計畫認列薪資費用$72,000，採權益法之長期股權投資收到現金 股利$127,500，交易目的證券投資分類為「透過損益按公允價值衡量之金融資產」期末評價損 失$12,000，簽發票據$198,000取得一筆土地。111年度折舊費用$78,000，權益法認列投資收 益$202,500，發行公司債$300,000。111年度應收帳款淨額增加$90,000，應付帳款減少$78,000， 存貨減少$27,000。111年度淨利$82,500，期初現金餘額$63,000。請問甲公司111年之營業活 動現金流量最接近金額為何？（註：請將「股利收取」作為營業活動之交易）', '["流入$4,500", "流入$28,500", "流入$433,500", "流出$115,500"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:26+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "322", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00218', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-111-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司的淨利率為20%，總資產報酬率為20%，平均資產總額除以平均股東權益比為3，則 股東權益報酬率為何？', '["40%", "50%", "60%", "70%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:26+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "322", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00219', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-111-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司 110 年度各項收益有$2,000,000，各項費損$1,000,000。綜合損益表各項收益中有 $800,000無須在110年度報稅，但應在111年度報稅。假設110年度及111年度所得稅稅率 均為20%，請問甲公司110年度的「遞延所得稅負債」有多少？', '["$108,000", "$160,000", "$200,000", "$300,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:26+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "322", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
