  ('heelevel3-7c4986e7-moex-00222', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-111-d3ff7f6b', 'sub-heelevel3-7c4986e7-03', NULL, 'single_choice', '假設經濟體系中有兩位消費者（A 和 B），兩種財貨（X 和 Y）。消費者 A 的初始稟賦為 （X=30,Y=20）而消費者 B的初始稟賦為（X=20,Y=30）。兩位消費者的效用函數皆為 U（X,Y）=X0.5Y0.5。均衡時兩位消費者的消費數量為何？', '["A（X=30,Y=20），B（X=20,Y=30）", "A（X=26,Y=24），B（X=24,Y=26）", "A（X=25,Y=25），B（X=25,Y=25）", "A（X=20,Y=30），B（X=30,Y=20）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:26+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "322", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00223', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-111-d3ff7f6b', 'sub-heelevel3-7c4986e7-03', NULL, 'single_choice', '若政府提高進口汽車關稅，下列敘述何者正確？', '["進口汽車銷售量增加", "進口汽車價格下跌", "國產汽車銷售量增加", "國產汽車價格下跌"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:26+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "322", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00224', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-111-d3ff7f6b', 'sub-heelevel3-7c4986e7-03', NULL, 'single_choice', '2016 年 10 月時，行政院為了推動長照 2.0 計畫，規劃以調高遺贈稅與菸稅來支應長照的財源需 求。依據財政部估計目前國內各種香菸平均售價約為65元，每包加收20元菸稅，則每年國人消 費的香菸將從原先 16.55 億包減少到 13.25 億包，根據上述資料計算消費香菸需求彈性之弧彈性 為何？', '["-0.17", "-0.65", "-0.83", "-1.05 32260、32560 32960、33060"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:26+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "322", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL)
